INSERT INTO "timer" ("id","sequence_id","timer_name","duration","timer_order","color","alarm_sound") VALUES ('913','njCKtJKhnSI','Game if ya gamer, otherwise idk give dome to a homie in need. Thousands of homies will go without head this winter season, but together we can lower this number. Your dome‑ation will help a homie bond with his local comemunity and feel at ease, if only for a 2 minutes. Its the season of giving and in a world where homies don''t know how to ask for help, offer it freely instead with a dome‑ation. So remember‑‑ a crank a day is not nearly enough. Give now, receive later 🤤','720','4','#0cd413','346328__steaq__bright-tibetan-bell-ding-b-note-cleaner.mp3');
